svg.script:
(function () {
  var colors = [
    '#e41a1c', // Red
    '#ff8c00', // Orange
    '#ffd92f', // Yellow
    '#4daf4a', // Green
    '#7fcef3', // Light Blue
    '#c7a6e8', // Light Purple
    '#f781bf', // Pink
    '#ffffff'  // White
  ];

  function cycleColor(region) {
    var current = Number(region.getAttribute('data-color-index') || 0);
    var next = (current + 1) % colors.length;
    region.setAttribute('data-color-index', String(next));
    region.setAttribute('fill', colors[next]);
  }

  function initialize() {
    var inputs = document.querySelectorAll('.region-input');
    for (var j = 0; j < inputs.length; j++) {
      inputs[j].addEventListener('click', function (event) { event.stopPropagation(); });
      inputs[j].addEventListener('keydown', function (event) { event.stopPropagation(); });
    }
    var regions = document.querySelectorAll('.clickable-region');
    for (var i = 0; i < regions.length; i++) {
      (function (region) {
        region.addEventListener('click', function () { cycleColor(region); });
        region.addEventListener('keydown', function (event) {
          if (event.key === 'Enter' || event.key === ' ') {
            event.preventDefault();
            cycleColor(region);
          }
        });
      }(regions[i]));
    }
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initialize);
  } else {
    initialize();
  }
}());
